output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(COUNT(DISTINCT ?game) AS ?total) WHERE {
  {
    VALUES ?year {
      1982 2006 2011 2013
    }
    ?series wdt:P31 wd:Q415767 ; wdt:P180 wd:Q11851 ; wdt:P585 ?date .
    BIND(YEAR(?date) AS ?seriesYear)
    FILTER(?seriesYear = ?year)
    ?game wdt:P1545 ?series ; wdt:P644 wd:Q651608 , wd:Q122710 .
  } UNION {
    ?series wdt:P31 wd:Q3577786 ; wdt:P180 wd:Q11851 ; wdt:P585 ?date .
    BIND(YEAR(?date) AS ?seriesYear)
    FILTER(?seriesYear = 2011)
    ?game wdt:P1545 ?series ; wdt:P644 wd:Q651608 , wd:Q122710 .
  }
}

